%[text] # Two-step FAVAR
%[text] Tutorial file for testing two-step FAVAR estimator
%[text:tableOfContents]{"heading":"**Table of Contents**"}
%%
%[text] ## Housekeeping
clear
close all %[output:7010ee89] %[output:2207c8b0] %[output:8c74ba13] %[output:3f0d3531] %[output:62a5e50c] %[output:7bf0c929] %[output:7b2cff2e] %[output:228b754b] %[output:65b7fd6c] %[output:74806f9a] %[output:5e16c751] %[output:59e665ee]

  
import factorTwostep.*

%%
%[text] ## Convenience functions
%[text] The `extremesFunc` function compresses any number of samples (draws from the posterior) into two numbers - the minimum and the maximum.
percentiles = [10, 50, 90];

prctileFunc = @(x) prctile(x, percentiles, 2);

extremesFunc = @(x) [min(x, [], 2), max(x, [], 2)];

medianFunc = @(x) median(x, 2);

defaultColors = get(0, "defaultAxesColorOrder");
%%
%[text] ## Number of Samples
numPresampled = 100;
%%
%[text] ## Prepare meta information for the models
%[text] 
%[text] Note that the meta information is common to all two-factor FAVAR models, regardless of the specific estimator used.
%[text] The properties specific to the two-step FAVAR are as follows:
%[text] **reducibleNames** – variables used for constructing the factors. 
%[text] **reducibleBlocks** – names of the blocks, indicating which block each reducible belongs to. Note that even if you have only one block, it must still be specified.Note that if you select the `"slowfast"` method in `blockType`, the group names must be `"slow"` and `"fast"`.
%[text] **blockType** – specifies which type of estimation method to use. Possible values are:
%[text] - `"blocks"` – default value, also used when there is only one block,
%[text] - `"slowfast"` – used for the slow–fast method. \
%[text] **numFactors** – defines how many factors to use for a given block.
estimStart = datex.m(1960,3);
estimEnd = datex.m(2001,8);
estimSpan = datex.span(estimStart, estimEnd);

meta = Meta( ...
    endogenousNames=["FYFF"],...
    exogenous=[],...
    order=13, ...
    intercept=false, ...
    estimationSpan=estimSpan, ...
    reducibleNames=["IPP" , "IPF" , "IPC" , "IPCD" , "IPCN" , "IPE" , "IPI" , "IPM" , "IPMD" , "IPMND" ,...
        "IPMFG" , "IPD" , "IPN" , "IPMIN" , "IPUT" , "IP" , "IPXMCA" , "PMI" , "PMP" , "GMPYQ" , "GMYXPQ" , ...
        "LHEL" , "LHELX" , "LHEM" , "LHNAG" , "LHUR" , "LHU680" , "LHU5" , "LHU14" , "LHU15" , "LHU26" ,...
        "LPNAG" , "LP" , "LPGD" , "LPMI" , "LPCC" , "LPEM" , "LPED" , "LPEN" , "LPSP" , "LPTU" , "LPT" ,...
        "LPFR" , "LPS" , "LPGOV" , "LPHRM" , "LPMOSA" , "PMEMP" , "GMCQ" , "GMCDQ" , "GMCNQ" , "GMCSQ" ,...
        "GMCANQ" , "HSFR" , "HSNE" , "HSMW" , "HSSOU" , "HSWST" , "HSBR" , "HMOB" , "PMNV" , "PMNO" , ...
        "PMDEL" , "MOCMQ" , "MSONDQ" , "FSNCOM" , "FSPCOM" , "FSPIN" , "FSPCAP" , "FSPUT" , "FSDXP" , ...
        "FSPXE" , "EXRSW" , "EXRJAN" , "EXRUK" , "EXRCAN" , "FYGM3" , "FYGM6" , "FYGT1" , "FYGT5" , ...
        "FYGT10" , "FYAAAC" , "FYBAAC" , "SFYGM3" , "SFYGM6" , "SFYGT1" , "SFYGT5" , "SFYGT10" , ...
        "SFYAAAC" , "SFYBAAC" , "FM1" , "FM2" , "FM3" , "FM2DQ" , "FMFBA" , "FMRRA" , "FMRNBA" , ...
        "FCLNQ" , "FCLBMC" , "CCINRV" , "PMCP" , "PWFSA" , "PWFCSA" , "PWIMSA" , "PWCMSA" , "PSM99Q" , ...
        "PUNEW" , "PU83" , "PU84" , "PU85" , "PUC" , "PUCD" , "PUS" , "PUXF" , "PUXHS" , "PUXM" , "LEHCC" , "LEHM" , "HHSNTN"], ...
    reducibleBlocks=["main", "main", "main", "main", "main", "main", "main", "main", ...
        "main", "main", "main", "main", "main", "main", "main", "main", "main", "main", ...
        "main", "main", "main", "main", "main", "main", "main", "main", "main", "main", ...
        "main", "main", "main", "main", "main", "main", "main", "main", "main", "main", ...
        "main", "main", "main", "main", "main", "main", "main", "main", "main", "main", ...
        "main", "main", "main", "main", "main", "main", "main", "main", "main", "main", ...
        "main", "main", "main", "main", "main", "main", "main", "main", "main", "main", ...
        "main", "main", "main", "main", "main", "main", "main", "main", "main", "main", ...
        "main", "main", "main", "main", "main", "main", "main", "main", "main", "main", ...
        "main", "main", "main", "main", "main", "main", "main", "main", "main", "main", ...
        "main", "main", "main", "main", "main", "main", "main", "main", "main", "main", ...
        "main", "main", "main", "main", "main", "main", "main", "main", "main", "main", "main"],...
    blockType = "blocks", ...    
    numFactors = struct("main",2), ...
    identificationHorizon=12);
%%
%[text] ## Specifying and loading input data

inputTbx = tablex.fromFile("data/FAVAR.csv");
dataH = DataHolder(meta, inputTbx);
%%
%[text] ## 
%[text] ## Reduced form models
%[text] 
%[text] The estimator-specific settings are always the same as those for the corresponding plain BVARs.
%[text] ### Basic FAVARs
%[text] 
%[text] #### **Minnesota priors**
%[text] **Sigma** – controls the priors used for calculating the covariance matrix. Possible values are:
%[text] - **ar** – uses the variances matrix from estimated AR models foer each variable (with the same order as the final model),
%[text] - **diag** – uses only the diagonal elements of the covariance matrix from an estimated VAR (with the same order as the final model),
%[text] - **full** – uses the full covariance matrix from an estimated VAR (with the same order as the final model). \
estimatorR1 = estimator.MinnesotaFAVARTwostep() %[output:2460982e]
%[text] #### 
%[text] #### **Normal Wishart priors**
%[text] **Sigma** – controls the priors used for calculating the covariance matrix. Possible values are:
%[text] - **ar** – uses the variances matrix from estimated AR models foer each variable (with the same order as the final model),
%[text] - **eye** – using the identity matrx \
% estimatorR1 = estimator.NormalWishartFAVARTwostep()
%[text] #### 
%[text] #### **Normal Diffuse priors**
%[text] There are no estimator-specific settings other than the hyperparameters.
% estimatorR1 = estimator.NormalDiffuseFAVARTwostep()
%[text] #### 
%[text] #### **Individual Normal Wishart priors**
%[text] **Sigma** – controls the priors used for calculating the covariance matrix. Possible values are:
%[text] - **ar** – uses the variances matrix from estimated AR models foer each variable (with the same order as the final model),
%[text] - **eye** – using the identity matrx \
% estimatorR1 = estimator.IndNormalWishartFAVARTwostep()
%[text] #### 
%[text] #### **Flat priors**
%[text] There are no estimator-specific settings other than the hyperparameters.
% estimatorR1 = estimator.FlatFAVARTwostep()
%[text] 
%[text] ### Stochastic volatility (SV) FAVARs
%[text] 
%[text] All SV models (including the general time varying model) share the same estimator specific setings
%[text] **HeteroskedasticityAutoRegression** – prior on the autoregression in heteroskedasticity (gamma in BEAR5)
%[text] **HeteroskedasticityShape** – prior on the shape of the inverse gamma distribution of the variance of the residual in heteroskedasticity (alpha in BEAR5)
%[text] **HeteroskedasticityScale** – prior on the scale of the inverse gamma distribution of the variance of the residual in heteroskedasticity (delta in BEAR5)
%[text] 
%[text] #### Standard SV model ( Cogley and Sargent (2005) )
% estimatorR1 = estimator.CogleySargentSVFAVAR()
%[text] #### SV model with Random Inertia 
%[text] 
%[text] **HeteroskedasticityAutoRegressionVariance** – prior on the variance of the autoregression in heteroskedasticity (zeta0 in BEAR5)
% estimatorR1 = estimator.RandomInertiaSVFAVAR()
%[text] #### 
%[text] #### SV model for large Bayesian VAR ( Carriero et al. (2012) )
% estimatorR1 = estimator.CogleySargentSVFAVAR()
%[text] ### 
%[text] ### Time-varying FAVARs
%[text] 
%[text] #### **Time varying dynamic parameters only**
%[text] There are no estimator-specific settings other than the hyperparameters.
% estimatorR1 = estimator.BetaTVFAVAR()
%[text] #### 
%[text] #### **Time varying dynamic parameters and stochastic volatility**
%[text] As mentioned above the common SV settings could be applied here as well
% estimatorR1 = estimator.GeneralTVFAVAR()
%[text] ### 
%[text] ### Creating the reduced form model

modelR1 = ReducedForm( ...
    meta=meta, ...
    dataHolder=dataH, ...
    estimator=estimatorR1 ...
);
%%
%[text] ## Estimation/sampling of the reduced form model 

modelR1.initialize();
info0 = modelR1.presample(numPresampled); %[output:155cca3c]
modelR1.Presampled{1}.beta %[output:0bc29398]

%%
%[text] ## Running Unconditional forecast 
%[text] 
%[text] ### Setting up the forecast range and run the forecast
fcastStart = datex.shift(modelR1.Meta.EstimationEnd, -10); %The forecast starts 10 periods prior to the end of the estimation span.
fcastEnd = datex.shift(modelR1.Meta.EstimationEnd, 0); %The forecast ends at the end of the estimation window.
fcastSpan = datex.span(fcastStart, fcastEnd);

fcastStart, fcastEnd %[output:5f51ad61] %[output:2188f798]

fcastTbx = modelR1.forecast(fcastSpan);
fcastPrctileTbx = tablex.apply(fcastTbx, prctileFunc);
fcastPrctileTbx = tablex.flatten(fcastPrctileTbx); %keeping only the pctiles set at the beginning of the file (10, 50, 90)


%[text] ### Visualize the unconditional forecast
chartpack.forecastPercentiles( ... %[output:group:8f8e1b0f] %[output:77e891b1] %[output:5da98854] %[output:17c556d6]
    fcastPrctileTbx, modelR1, FigureTitle ="Unconditional forecast") %[output:group:8f8e1b0f] %[output:77e891b1] %[output:5da98854] %[output:17c556d6]

%%
%[text] ## Identification
%[text] 
%[text] ### Cholesky
%[text] 
%[text] #### Setting up the identifier
identChol = identifier.Cholesky(order=[]);

modelS1 = Structural(reducedForm=modelR1, identifier=identChol);
modelS1.initialize();

info1 = modelS1.presample(numPresampled);
modelS1.Presampled{1}
%[text] #### 
%[text] #### Checking transition matrices
modelS1.Presampled{1}.IdentificationDraw
modelS1.Presampled{1}.IdentificationDraw.A{1,1}
modelS1.Presampled{1}.IdentificationDraw.A{2,1}
%[text] #### 
%[text] #### Checking scaling matrix
modelS1.Presampled{1}.D
modelS1.Presampled{2}.D

%%
%[text] ## Impulse responses (IRF)
%[text] 
%[text] ### Cholesky
respTbl1 = modelS1.simulateResponses();
respTbl1 = tablex.apply(respTbl1, prctileFunc);
respTbl1 = tablex.flatten(respTbl1);

respTbl1

chartpack.responsePercentiles( ...
    respTbl1, modelS1 ...
    , "figureTitle", "Shock responses (percentiles)" ...
);

%%
%[text] ## **Historical shock decomposition**
%[text] 
histContTbx = modelS1.calculateContributions();

tablex.getHigherDims(histContTbx)

histContMedTbx = tablex.apply(histContTbx, medianFunc);

chartpack.contributionsMedian( ...
    histContMedTbx, modelS1 ...
    , "figureTitle", "Shock contributions with Cholesky (median)" ...
);
%%
%[text] ## **Unconditional forecast shock decomposition**
%[text] 

[uncFcastTbl1, uncFcastContribTbl1] = modelS1.forecast( ...
    fcastSpan, ...
    contributions=true ...
);

tablex.getHigherDims(uncFcastContribTbl1)

contMedTbx = tablex.apply(uncFcastContribTbl1, medianFunc);

chartpack.contributionsMedian( ...
    contMedTbx, modelS1 ...
    , "figureTitle", "Unconditional forecast Shock contributions (median)" ...
);

%%
%[text] ## **FEVD**

fevdTbx = modelS1.calculateFEVD();

tablex.getHigherDims(fevdTbx)

fevdMedTbx = tablex.apply(fevdTbx, medianFunc);

chartpack.contributionsMedian( ...
    fevdMedTbx, modelS1 ...
    , "figureTitle", "FEVD (median)" ...
);


%%
%[text] ## Conditional forecast
%[text] 
%[text] ### Setting up the conditions and the forecast plan
condDataTbl = tablex.fromFile("data/condDataTblFAVAR.xlsx");
planTbl = tablex.readConditioningPlan("data/planTblFAVAR.xlsx");
%[text] ### 
%[text] ### Setting up the forecast range 
cfcastSpan = fcastSpan;
%[text] ### 
%[text] ### Running conditional forecast with no simulation plan
[condFcastTbl1, condFcastContribTbl1] = modelS1.conditionalForecast( ...
    cfcastSpan, ...
    conditions=condDataTbl, ...
    plan=[], ...
    exogenousFrom = "conditions" ...
);


condFcastPrctilesTbl1 = tablex.apply(condFcastTbl1, prctileFunc);
%[text] ### 
%[text] ### Running conditional forecast with simulation plan
[condFcastTbl2, condFcastContribTbl2] = modelS1.conditionalForecast( ...
    cfcastSpan, ...
    conditions=condDataTbl, ...
    plan=planTbl, ...
    exogenousFrom = "conditions" ...
);


condFcastPrctilesTbl2 = tablex.apply(condFcastTbl2, prctileFunc);
%[text] ### 
%[text] ### Visualize the conditional forecast
chartpack.conditionalForecastPercentiles( ...
    condFcastPrctilesTbl1, modelS1 ...
    , "figureTitle", "Conditional forecast w/o plan (percentiles)" ...
);

chartpack.conditionalForecastPercentiles( ...
    condFcastPrctilesTbl2, modelS1 ...
    , "figureTitle", "Conditional forecast with plan (percentiles)" ...
);

